require\("dotenv"\).config\({ path: ".env.local" }\);
const s = require\("@supabase/supabase-js"\).createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY\);
\(async \(\) => {
    const { data: p } = await s.from\("provinces"\).select\("id"\).eq\("slug", "new-brunswick"\).single\(\);
    const { data: all } = await s.from\("ranges"\).select\("name, post_images"\).eq\("province_id", p.id\).order\("name"\);
    for \(const r of all\) {
        let imgs = r.post_images || [];
        if \(typeof imgs === "string"\) try { imgs = JSON.parse\(imgs\); } catch { imgs = [imgs]; }
        if \(!Array.isArray\(imgs\)\) imgs = [imgs];
        const first = imgs[0] || "EMPTY";
        const label = first === "/filler-image.jpg" ? "FILLER" : first.substring\(0, 60\);
        console.log\(r.name + " => " + label\);
    }
}\)\(\);
')
